export default function Banner({ data = defaultBannerData }) {
  const {
    badge = defaultBannerData.badge,
    heading = defaultBannerData.heading,
    subtext = defaultBannerData.subtext,
    backgroundImage = defaultBannerData.backgroundImage,
    buttons = defaultBannerData.buttons,
  } = data || {};

  return (
    <section className="relative w-full min-h-[320px] lg:min-h-[450px] flex items-center overflow-hidden">
      {/* Optimized Background Image */}
      <Image
        src={backgroundImage}
        alt="Banner background"
        fill
        priority
        sizes="100vw"
        className="object-cover"
      />
      {/* Dark overlay */}
      <div className="absolute inset-0 bg-black/55 z-10" />

      <MaxWidthContainer className="w-full flex justify-center items-center relative z-20">
        <div className="relative max-w-175 flex flex-col items-center text-center gap-4 lg:gap-8.75 py-16 px-4 sm:px-6 lg:px-0 ">
          <div className="text-center flex flex-col items-center">
            {/* Badge */}
            <div className="flex items-center gap-2 px-2 py-1 lg:px-4.75 lg:py-1.75 border border-primary rounded-full w-fit">
              <span className="text-primary max-lg:text-xs font-semibold leading-normal">
                {badge}
              </span>
            </div>

            {/* Heading */}
            <h1 className="text-white h2 lg:text-[36px] tracking-tight lg:h1 font-bold leading-normal mt-1">
              {heading}
            </h1>

            {/* Subtext */}
            <p className="text-white/90 text-sm lg:text-[20px]  leading-normal mt-1 lg:mt-2">
              {subtext}
            </p>
          </div>

          {/* Buttons */}
          <div className="flex flex-wrap items-center justify-center gap-4 mt-2">
            {buttons.map((btn) => (
              <a
                key={btn.id}
                href={btn.href}
                className={`flex items-center gap-1 px-4.75 py-3 rounded-xl text-base font-bold leading-normal transition-all duration-200
                  ${
                    btn.variant === "primary"
                      ? "bg-primary text-text-primary hover:bg-primary-hover"
                      : "bg-black text-white border border-white/80 hover:bg-text-secondary"
                  }`}
              >
                <span className="w-6 h-6">{buttonIcons[btn.id]}</span>
                {btn.label}
              </a>
            ))}
          </div>
        </div>
      </MaxWidthContainer>
    </section>
  );
}
